    #getting the correct maze for the rounf
    def getMaze(roundNum):
        if roundNum == 1:
            return mazes.maze1
        elif roundNum == 2:
            return mazes.maze2
        elif roundNum == 3:
            return mazes.maze3
        elif roundNum == 4:
            return mazes.maze4
        elif roundNum == 5:
            return mazes.maze5

    #printing the maze in the correct layout
    def printMaze(maze):
        for i in maze:
            for j in i:
                print(j, end="")
            print(" ")
